const fs = require('fs');
const path = require('path');
const config = require('../config');

const LOCK_FILE = '/tmp/tom_hum_api.lock';
const RATE_GATE_MS = config.API_RATE_GATE_MS || 5000;

/**
 * API Rate Gate — file-based locking để ngăn 11 daemons call API cùng lúc
 * Min 5s giữa mỗi API call via file lock
 */
class ApiRateGate {
  /**
   * Acquire lock — chờ cho đến khi có thể gọi API
   * File lock tự động release sau RATE_GATE_MS
   */
  async acquire() {
    while (true) {
      try {
        // Check if lock exists and still valid
        if (fs.existsSync(LOCK_FILE)) {
          const stat = fs.statSync(LOCK_FILE);
          const age = Date.now() - stat.mtimeMs;

          if (age < RATE_GATE_MS) {
            // Lock còn hiệu lực — wait and retry
            await sleep(500);
            continue;
          } else {
            // Lock expired — xóa và thử acquire
            fs.unlinkSync(LOCK_FILE);
          }
        }

        // Try to acquire lock
        fs.writeFileSync(LOCK_FILE, `${process.pid}\n${Date.now()}`);

        // Double-check (race condition protection)
        await sleep(100);
        const content = fs.readFileSync(LOCK_FILE, 'utf8');
        if (content.startsWith(String(process.pid))) {
          // Success — we own the lock
          return;
        }

        // Someone else took the lock — retry
        await sleep(500);
      } catch (err) {
        // File I/O error — retry
        await sleep(500);
      }
    }
  }

  /**
   * Release lock (optional — lock auto-expires sau RATE_GATE_MS)
   */
  release() {
    try {
      if (fs.existsSync(LOCK_FILE)) {
        const content = fs.readFileSync(LOCK_FILE, 'utf8');
        if (content.startsWith(String(process.pid))) {
          fs.unlinkSync(LOCK_FILE);
        }
      }
    } catch (err) {
      // Ignore errors on release
    }
  }
}

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

module.exports = new ApiRateGate();

