  // Skip non-existent projects
  if (!fs.existsSync(projectDir)) {
    continue;
  }

  if (!state.completedTasks[project]) state.completedTasks[project] = [];

  // HUNTER AGENT: Decoupled to `hunter-daemon.js` (Hot Reload Architecture)
  // See implementation_plan.md -> Immortal Swarm

  // Find next incomplete, applicable task (Priority 2)
  const nextTask = config.BINH_PHAP_TASKS.find(t => {
    if (state.completedTasks[project].includes(t.id)) return false;

    if (!isTaskApplicable(t.id, projectDir)) {
      state.completedTasks[project].push(t.id);
      log(`AUTO-CTO: Skipping ${t.id} for ${project} — not applicable`);
      return false;
    }
    return true;
  });

  if (nextTask) {
    const complexity = classifyComplexity(nextTask, project);
    const missionResult = generateMissionPrompt(nextTask, project, complexity);
    const filename = `mission_${project.replace(/-/g, '_')}_auto_${nextTask.id}.txt`;
    fs.writeFileSync(path.join(config.WATCH_DIR, filename), missionResult.prompt);
    state.completedTasks[project].push(nextTask.id);
    state.totalTaskCounter++;
    const done = state.completedTasks[project].length;
    const total = config.BINH_PHAP_TASKS.length;
    log(`AUTO-CTO: Generated ${nextTask.id} for ${project} [${complexity.toUpperCase()}] (${done}/${total}) [${phase}]`);
    saveState(state);
    return;
  }
}

// No tasks found in pool — check if all done
const allDone = config.ALL_PROJECTS.every(p => {
  const completed = (state.completedTasks[p] || []).length;
  return completed >= config.BINH_PHAP_TASKS.length || !fs.existsSync(resolveProjectDir(p));
});

if (allDone) {
  log('AUTO-CTO: 🏆 ALL projects ALL tasks complete! DNA-First mission accomplished.');
} else {
  log(`AUTO-CTO: No tasks in current pool [${phase}] — will try next cycle`);
}
saveState(state);

