  try {
    const state = loadState();
    if (!state.completedTasks) state.completedTasks = {};
    if (typeof state.currentProjectIdx !== 'number') state.currentProjectIdx = 0;
    if (typeof state.totalTaskCounter !== 'number') state.totalTaskCounter = 0;

